using System.ComponentModel.DataAnnotations;
using System.ComponentModel.DataAnnotations.Schema;
using Microsoft.EntityFrameworkCore;

namespace WoodseatsScouts.Coins.Api.Models.Domain;

public class Coin
{
    public int Id { get; set; }
    
    public int ActivityBaseSequenceNumber { get; set; }
    
    public int ActivityBaseId { get; set; }
    
    public required ActivityBase ActivityBase { get; set; }

    public int Value { get; set; }

    /// <summary>
    /// Autogenerated externally before going live, unlike Member's code which is computed as members can be added after app is live.
    /// </summary>
    [StringLength(16)]
    public required string Code { get; set; }

    public int? MemberId { get; set; }
    
    public ScoutMember? Member { get; set; }
    
    public DateTime? LockUntil { get; set; }
}